// src/services/upload.service.ts
async function uploadImage(source, folder = "projects") {
  const input = Buffer.isBuffer(source) ? `data:image/webp;base64,${source.toString("base64")}` : source;
  const result2 = await import_cloudinary.v2.uploader.upload(input, {
    folder: `nonedev/${folder}`,
    transformation: [
      { width: 1200, height: 675, crop: "fill", gravity: "auto" },
      { quality: "auto", fetch_format: "auto" }
    ]
  });
  return {
    url: result2.secure_url,
    publicId: result2.public_id,
    width: result2.width,
    height: result2.height,
    format: result2.format,
    bytes: result2.bytes
  };
}

// src/controllers/upload.controller.ts
var ALLOWED_TYPES = ["image/jpeg", "image/png", "image/webp", "image/gif"];
var MAX_BYTES = 8 * 1024 * 1024;
var uploadImageHandler = async (c) => {
  const formData = await c.req.formData().catch(() => null);
  if (!formData) return c.json({ error: "Expected multipart/form-data" }, 400);
  const file = formData.get("file");
  const folder = formData.get("folder") ?? "projects";
  if (!file || !(file instanceof File)) {
    return c.json({ error: "Missing field: file" }, 400);
  }
  if (!ALLOWED_TYPES.includes(file.type)) {
    return c.json({ error: `Unsupported type: ${file.type}. Allowed: jpeg, png, webp, gif` }, 415);
  }
  if (file.size > MAX_BYTES) {
    return c.json({ error: "File too large (max 8 MB)" }, 413);
  }
  if (folder !== "projects" && folder !== "articles") {
    return c.json({ error: 'folder must be "projects" or "articles"' }, 400);
  }
  const arrayBuffer = await file.arrayBuffer();
  const buffer2 = Buffer.from(arrayBuffer);
  const result2 = await uploadImage(buffer2, folder);
  return c.json({ data: result2 }, 201);
};

// src/routes/upload.route.ts
var uploadRouter = new Hono2();
uploadRouter.post("/", authMiddleware, uploadImageHandler);

